units.exampleCode:
#include <iostream>
using namespace std;

int main() {
    int a = 10;     // 变量声明，末尾有分号
    cout << a;      // 输出语句，末尾有分号
    a = a + 1;      // 赋值语句，末尾有分号
    return 0;       // return 语句，末尾有分号
}

#include <iostream>
using namespace std;

int main() {                    // main 函数开始
    int x = 10;
    if (x > 5) {                // if 代码块开始
        cout << "x 大于 5" << endl;
    }                           // if 代码块结束
    return 0;
}                               // main 函数结束

#include <iostream>
using namespace std;

int main() {
    // 这是单行注释
    cout << "Hello" << endl; // 行末注释

    /*
     * 这是多行注释
     * 可以写很多行
     */
    cout << "World" << endl;
    return 0;
}

